import React, { Component } from "react";
import { Progress } from "reactstrap";
import { Link } from "react-router-dom";

import config from "./config";
import ControlsModal from "./ControlsModal";
import CheatsModal from "./CheatsModal";
import Emulator from "./Emulator";
import RomLibrary from "./RomLibrary";
import { PREDEFINED_CHEATS } from "./CheatManager";
// import NESCntlr from 'nes-cntlr';


import "./RunPage.css";
import VirtualController from "./VirtualController";

function loadBinary(path, callback, handleProgress) {
  var req = new XMLHttpRequest();
  req.open("GET", path);
  req.overrideMimeType("text/plain; charset=x-user-defined");
  req.onload = function () {
    if (this.status === 200) {
      if (req.responseText.match(/^<!doctype html>/i)) {
        // Got HTML back, so it is probably falling back to index.html due to 404
        return callback(new Error("Page not found"));
      }

      callback(null, this.responseText);
    } else if (this.status === 0) {
      // Aborted, so ignore error
    } else {
      callback(new Error(req.statusText));
    }
  };
  req.onerror = function () {
    callback(new Error(req.statusText));
  };
  req.onprogress = handleProgress;
  req.send();
  return req;
}

/*
 * The UI for the emulator. Also responsible for loading ROM from URL or file.
 */
class RunPage extends Component {
  constructor(props) {
    super(props);
    this.state = {
      romName: null,
      romData: null,
      running: false,
      paused: false,
      controlsModalOpen: false,
      loading: true,
      loadedPercent: 3,
      error: null,
      cheatsModalOpen: false,
      cheatsList: [],
      newCheatName: "",
      newCheatCode: "",
      isFullscreen: false,
      aspectRatio: "4:3",
      windowWidth: window.innerWidth
    };
  }

  render() {
    return (
      <div className="RunPage">
        {/* <ul className="navbar-nav ml-auto mr-auto">
            <li className="navitem">
             <p><span className="navbar-text mr-3">{this.state.romName}</span></p> 
             <p><span className="navbar-text mr-3">DPad: Setas | Start: Enter | Select: CTRL Direito | Botão A: Z | Botão B: X</span></p>
            </li>
          </ul> */}
        <div className="runpage-container">

          {/* <Button
                outline
                color="primary"
                onClick={this.toggleControlsModal}
                className="mr-3"
              >
                Controles
              </Button>  */}

          {/* <Button
                outline
                color="primary"
                onClick={this.handlePauseResume}
                disabled={!this.state.running}
              >
                {this.state.paused ? "Continue" : "Pause"}
              </Button> */}
          {this.state.error ? (
            this.state.error
          ) : (
            <div
              id="screen-container-root"
              className={`screen-container${this.state.isFullscreen ? ' fullscreen-active' : ''}`}
              ref={el => {
                this.screenContainer = el;
              }}
            >
              <div className="emulator-menu" style={{ padding: this.state.isFullscreen ? "10px" : "0", background: this.state.isFullscreen ? "rgba(0,0,0,0.85)" : "transparent" }}>
                {!this.state.isFullscreen && (
                  <div>
                    <p style={{ margin: "0", fontWeight: "bold" }}>{this.state.romName}</p>
                  </div>
                )}
                {!this.state.isFullscreen && (
                  <p className="keyboard-shortcuts-info" style={{ margin: "0", fontSize: "0.9em", color: "#888" }}>Padrão: DPad: Setas | Start: Enter | Select: CTRL | Botão A: X | Botão B: Z</p>
                )}
                <div style={{ marginTop: this.state.isFullscreen ? "0" : "5px" }}>
                  {this.state.paused ? (
                    <a style={{ "text-decoration": "none", cursor: "pointer" }} onClick={this.handlePauseResume} className="no-underline"> Continuar Emulador ( <i className="fa fa-play-circle "></i> ) </a>
                  ) : (
                    <a style={{ "text-decoration": "none", cursor: "pointer" }} onClick={this.handlePauseResume} className="no-underline"> Pausar Emulador ( <i className="fa fa-pause"></i> ) </a>
                  )}

                  <span className="btn-fullscreen-container">
                    {" "}-{" "}
                    <a style={{ "text-decoration": "none", cursor: "pointer" }} onClick={this.toggleFullscreen} className="no-underline">
                      {this.state.isFullscreen ? "Sair de Tela Cheia" : "Tela Cheia"}{" "}
                      ( <i className={this.state.isFullscreen ? "fa fa-compress" : "fa fa-arrows-alt"}></i> )
                    </a>
                    <span className="aspect-ratio-container">
                      {" "}( <a onClick={() => this.setAspectRatio(this.state.aspectRatio === '4:3' ? '16:9' : '4:3')} style={{ cursor: 'pointer', textDecoration: "none" }}>
                        {this.state.aspectRatio === '4:3' ? '16:9' : '4:3'}
                      </a> )
                    </span>
                  </span>

                  {" "}- <a style={{ "text-decoration": "none", cursor: "pointer" }} onClick={this.handleReset} className="no-underline"> Resetar Emulador ( <i className="fa fa-refresh"></i> ) </a>
                  {" "}- <a style={{ "text-decoration": "none", cursor: "pointer" }} onClick={this.toggleControlsModal} className="no-underline"> Configurar Controles ( <i className="fa fa-gamepad"></i> )</a>
                  {" "}- <a style={{ "text-decoration": "none", cursor: "pointer" }} onClick={this.toggleCheatsModal} className="no-underline"> Trapaças / Cheats ( <i className="fa fa-magic"></i> )</a>
                </div>
              </div>
              {this.state.loading ? (
                <Progress
                  value={this.state.loadedPercent}
                  style={{
                    position: "absolute",
                    width: "70%",
                    left: "15%",
                    top: "48%"
                  }}
                />
              ) : this.state.romData ? (
                <div className="emulator-wrapper" style={{ position: "relative", flexGrow: 1, minHeight: 0, display: "flex", justifyContent: "center", alignItems: "center", width: "100%" }}>
                  <Emulator
                    romData={this.state.romData}
                    paused={this.state.paused}
                    activeCheats={this.state.cheatsList}
                    aspectRatio={this.state.aspectRatio}
                    ref={emulator => {
                      this.emulator = emulator;
                    }}
                  />

                  {/* TODO: lift keyboard and gamepad state up */}
                  {this.state.controlsModalOpen && (
                    <ControlsModal
                      isOpen={this.state.controlsModalOpen}
                      toggle={this.toggleControlsModal}
                      keys={this.emulator.keyboardController.keys}
                      setKeys={this.emulator.keyboardController.setKeys}
                      promptButton={this.emulator.gamepadController.promptButton}
                      gamepadConfig={this.emulator.gamepadController.gamepadConfig}
                      setGamepadConfig={
                        this.emulator.gamepadController.setGamepadConfig
                      }
                    />
                  )}
                  {this.state.cheatsModalOpen && (
                    <CheatsModal
                      isOpen={this.state.cheatsModalOpen}
                      toggle={this.toggleCheatsModal}
                      cheatsList={this.state.cheatsList}
                      handleToggleCheat={this.handleToggleCheat}
                      handleRemoveCheat={this.handleRemoveCheat}
                      handleAddCheat={this.handleAddCheat}
                      newCheatName={this.state.newCheatName}
                      newCheatCode={this.state.newCheatCode}
                      setNewCheatName={(val) => this.setState({ newCheatName: val })}
                      setNewCheatCode={(val) => this.setState({ newCheatCode: val })}
                    />
                  )}
                </div>
              ) : null}
              <div style={{ "z-index": "10000" }} id="nes-pad">
                <VirtualController />
              </div>


            </div>
          )}
        </div>
        <nav
          className="navbar"
          ref={el => {
            this.navbar = el;
          }}
        >
        </nav>
      </div>
    );
  }

  componentDidMount() {
    window.addEventListener("resize", this.layout);
    document.addEventListener("fullscreenchange", this.handleFullscreenChange);
    document.addEventListener("webkitfullscreenchange", this.handleFullscreenChange);
    document.addEventListener("mozfullscreenchange", this.handleFullscreenChange);
    document.addEventListener("MSFullscreenChange", this.handleFullscreenChange);

    this.layout();
    this.load();
    // let player1 = new NESCntlr({
    //   virtual: 'always',
    //   location: '#controle-nes'
    // });

    // player1.init();

  }

  componentWillUnmount() {
    window.removeEventListener("resize", this.layout);
    document.removeEventListener("fullscreenchange", this.handleFullscreenChange);
    document.removeEventListener("webkitfullscreenchange", this.handleFullscreenChange);
    document.removeEventListener("mozfullscreenchange", this.handleFullscreenChange);
    document.removeEventListener("MSFullscreenChange", this.handleFullscreenChange);

    if (this.currentRequest) {
      this.currentRequest.abort();
    }
  }

  toggleFullscreen = () => {
    const element = this.screenContainer;
    if (!element) return;

    if (!document.fullscreenElement && !document.webkitFullscreenElement && !document.mozFullScreenElement && !document.msFullscreenElement) {
      if (element.requestFullscreen) {
        element.requestFullscreen();
      } else if (element.webkitRequestFullscreen) {
        element.webkitRequestFullscreen();
      } else if (element.mozRequestFullScreen) {
        element.mozRequestFullScreen();
      } else if (element.msRequestFullscreen) {
        element.msRequestFullscreen();
      }
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      } else if (document.webkitExitFullscreen) {
        document.webkitExitFullscreen();
      } else if (document.mozCancelFullScreen) {
        document.mozCancelFullScreen();
      } else if (document.msExitFullscreen) {
        document.msExitFullscreen();
      }
    }
  };

  handleFullscreenChange = () => {
    const isFullscreen = !!(document.fullscreenElement || document.webkitFullscreenElement || document.mozFullScreenElement || document.msFullscreenElement);

    let newAspectRatio = this.state.aspectRatio;
    // Em telas médias (tablets), força a proporção 4:3 se entrar em fullscreen
    if (isFullscreen && window.innerWidth < 1024) {
      newAspectRatio = "4:3";
    }

    this.setState({ isFullscreen, aspectRatio: newAspectRatio }, () => {
      setTimeout(() => {
        this.layout();
      }, 100);
    });
  };

  setAspectRatio = (ratio) => {
    if (window.innerWidth >= 1024) {
      this.setState({ aspectRatio: ratio }, () => {
        this.layout();
      });
    }
  };

  layout = () => {
    const isTouch = (('ontouchstart' in window) ||
      (navigator.maxTouchPoints > 0) ||
      (navigator.msMaxTouchPoints > 0));

    const isMobile = window.innerWidth < 768;
    const isFullscreen = !!(document.fullscreenElement || document.webkitFullscreenElement || document.mozFullScreenElement || document.msFullscreenElement);

    this.setState({ isFullscreen });

    const wrapperEl = document.querySelector('.emulator-wrapper');

    if (isFullscreen) {
      // Em modo Fullscreen: o screen-container sempre ocupa 100% da tela (100vh)
      this.screenContainer.style.height = "100vh";

      // Ajustamos o padding inferior do wrapper para evitar sobreposição do controle
      let paddingBottom = 0;
      if (isTouch) {
        const cntlrEl = document.querySelector('.cntlr');
        if (cntlrEl) {
          const cntlrBottom = parseFloat(window.getComputedStyle(cntlrEl).bottom) || 0;
          paddingBottom = cntlrEl.getBoundingClientRect().height + cntlrBottom + 15;
        }
      }
      if (wrapperEl) {
        wrapperEl.style.paddingBottom = `${paddingBottom}px`;
      }
    } else {
      // Fora de Fullscreen
      if (wrapperEl) {
        wrapperEl.style.paddingBottom = "0px";
      }

      // No fluxo normal da página do site
      let offset = 145; // Altura padrão do cabeçalho
      if (isTouch) {
        const cntlrEl = document.querySelector('.cntlr');
        if (cntlrEl) {
          const cntlrBottom = parseFloat(window.getComputedStyle(cntlrEl).bottom) || 0;
          offset += cntlrEl.getBoundingClientRect().height + cntlrBottom + 15;
        } else {
          offset += 165;
        }
      }

      this.screenContainer.style.height = `${window.innerHeight - offset}px`;
    }

    if (this.emulator) {
      requestAnimationFrame(() => {
        if (this.emulator) {
          this.emulator.fitInParent();
        }
      });
    }
  };

  load = () => {
    if (true) {
      const eggs = ["gradius", "lf", "contra", "dh", "duckh", "sevensix", "tn2", "cv"];
      var egg = eggs[Math.floor(Math.random() * eggs.length)];
      // var egg = "cv";

      const slug = egg;
      const predefined = PREDEFINED_CHEATS[slug] || [];
      const cheatsList = predefined.map(cheat => ({ ...cheat, enabled: false }));
      this.setState({ cheatsList });

      const isLocalROM = /^local-/.test(slug);
      const romHash = slug.split("-")[1];
      const romInfo = isLocalROM
        ? RomLibrary.getRomInfoByHash(romHash)
        : config.ROMS[slug];

      if (!romInfo) {
        this.setState({ error: `ROM inválida: ${slug}` });
        return;
      }

      if (isLocalROM) {
        this.setState({ romName: romInfo.name });
        const localROMData = localStorage.getItem("blob-" + romHash);
        this.handleLoaded(localROMData);
      } else {
        this.setState({ romName: romInfo.description });
        this.currentRequest = loadBinary(
          romInfo.url,
          (err, data) => {
            if (err) {
              this.setState({ error: `Error loading ROM: ${err.message}` });
            } else {
              this.handleLoaded(data);
            }
          },
          this.handleProgress
        );
      }
    } else if (this.props.location.state && this.props.location.state.file) {
      let reader = new FileReader();
      reader.readAsBinaryString(this.props.location.state.file);
      reader.onload = e => {
        this.currentRequest = null;
        this.handleLoaded(reader.result);
      };
    } else {
      this.setState({ error: "No ROM provided" });
    }
  };

  handleProgress = e => {
    if (e.lengthComputable) {
      this.setState({ loadedPercent: (e.loaded / e.total) * 100 });
    }
  };

  handleLoaded = data => {
    this.setState({ running: true, loading: false, romData: data }, () => {
      setTimeout(() => {
        this.layout();
      }, 100);
    });
  };

  handlePauseResume = () => {
    this.setState({ paused: !this.state.paused });
  };

  handleReset = () => {
    if (this.emulator) {
      this.emulator.reset();
    }
  };

  layout = () => {
    let navbarHeight = parseFloat(window.getComputedStyle(this.navbar).height);

    const isTouch = (('ontouchstart' in window) ||
      (navigator.maxTouchPoints > 0) ||
      (navigator.msMaxTouchPoints > 0));

    let offset = 145;
    if (isTouch) {
      const cntlrEl = document.querySelector('.cntlr');
      if (cntlrEl) {
        offset += cntlrEl.getBoundingClientRect().height + 15;
      } else {
        offset += 165; // Fallback default
      }
    }

    this.screenContainer.style.height = `${window.innerHeight - offset}px`;
    if (this.emulator) {
      this.emulator.fitInParent();
    }
  };

  toggleControlsModal = () => {
    const nextState = !this.state.controlsModalOpen;
    if (nextState) {
      this.wasPausedBeforeModal = this.state.paused;
      this.setState({ paused: true, controlsModalOpen: true });
    } else {
      const restorePause = this.wasPausedBeforeModal !== undefined ? this.wasPausedBeforeModal : false;
      this.setState({ paused: restorePause, controlsModalOpen: false });
    }
  };

  toggleCheatsModal = () => {
    const nextState = !this.state.cheatsModalOpen;
    if (nextState) {
      this.wasPausedBeforeModal = this.state.paused;
      this.setState({ paused: true, cheatsModalOpen: true });
    } else {
      const restorePause = this.wasPausedBeforeModal !== undefined ? this.wasPausedBeforeModal : false;
      this.setState({ paused: restorePause, cheatsModalOpen: false });
    }
  };

  handleToggleCheat = (index) => {
    const cheatsList = this.state.cheatsList.map((cheat, i) => {
      if (i === index) {
        return { ...cheat, enabled: !cheat.enabled };
      }
      return cheat;
    });
    this.setState({ cheatsList });
  };

  handleAddCheat = (e) => {
    e.preventDefault();
    const name = this.state.newCheatName || "";
    const code = (this.state.newCheatCode || "").trim().toUpperCase();

    if (!name || !code) {
      alert("Por favor, preencha o nome e o código do cheat.");
      return;
    }

    const GG_REGEX = /^[APZLGITYEOXUKSVN]{6,8}$/;
    if (!GG_REGEX.test(code)) {
      alert("Código Game Genie inválido! O código deve ter 6 ou 8 letras e conter apenas os caracteres permitidos: A P Z L G I T Y E O X U K S V N");
      return;
    }

    const newCheat = { name, code, enabled: true, custom: true };
    this.setState({
      cheatsList: [...this.state.cheatsList, newCheat],
      newCheatName: "",
      newCheatCode: ""
    });
  };

  handleRemoveCheat = (index) => {
    const cheatsList = this.state.cheatsList.filter((_, i) => i !== index);
    this.setState({ cheatsList });
  };
}

export default RunPage;
